-- sdss_umag from SVO SLOAN/SDSS.u
-- n_profile_rows=47
-- stats: average=3572.18240032 A, cdf05=3235.3511236 A, cdf95=3857.58575884 A, zeropoint_jy=NULL
-- zeropoint_jy staging skipped for this filter.
-- sample 1: wavelength_angstrom=2980, relative_spectral_response=0

SELECT
  'sdss_umag' AS `moca_psid`,
  ps.`average_wavelength` AS `current_average_wavelength`,
  3572.18240032 AS `proposed_average_wavelength`,
  ps.`min_wavelength` AS `current_min_wavelength`,
  3235.3511236 AS `proposed_min_wavelength`,
  ps.`max_wavelength` AS `current_max_wavelength`,
  3857.58575884 AS `proposed_max_wavelength`
FROM `moca_photometry_systems` ps
WHERE ps.`moca_psid` = 'sdss_umag'
  AND (
    (ps.`average_wavelength` IS NOT NULL AND 3572.18240032 IS NOT NULL AND ABS(ps.`average_wavelength` - 3572.18240032) > 1e-6)
    OR (ps.`min_wavelength` IS NOT NULL AND 3235.3511236 IS NOT NULL AND ABS(ps.`min_wavelength` - 3235.3511236) > 1e-6)
    OR (ps.`max_wavelength` IS NOT NULL AND 3857.58575884 IS NOT NULL AND ABS(ps.`max_wavelength` - 3857.58575884) > 1e-6)
  );

SELECT
  'sdss_umag' AS `moca_psid`,
  ps.`zeropoint_jansky` AS `current_zeropoint_jansky`,
  NULL AS `proposed_zeropoint_jansky`
FROM `moca_photometry_systems` ps
WHERE ps.`moca_psid` = 'sdss_umag'
  AND ps.`zeropoint_jansky` IS NOT NULL
  AND NULL IS NOT NULL
  AND ABS(ps.`zeropoint_jansky` - NULL) > 1e-9;

UPDATE `moca_photometry_systems`
SET
  `average_wavelength` = COALESCE(`average_wavelength`, 3572.18240032),
  `min_wavelength` = COALESCE(`min_wavelength`, 3235.3511236),
  `max_wavelength` = COALESCE(`max_wavelength`, 3857.58575884),
  `zeropoint_jansky` = COALESCE(`zeropoint_jansky`, NULL),
  `bandpass_file` = COALESCE(`bandpass_file`, 'SVO FPS SLOAN/SDSS.u')
WHERE `moca_psid` = 'sdss_umag';

